import { createContext, useContext, useState, useEffect } from "react";

const AuthContext = createContext(null);

// ── Backend URL ──
const API = "http://localhost:5000/api";

export function AuthProvider({ children }) {
  const [user, setUser]       = useState(null);
  const [loading, setLoading] = useState(true);

  // ── On app load — check if user was already logged in ──
  useEffect(() => {
    const token       = localStorage.getItem("bhojan_token");
    const savedUser   = localStorage.getItem("bhojan_user");
    if (token && savedUser) {
      setUser(JSON.parse(savedUser));
    }
    setLoading(false);
  }, []);

  // ── Signup — calls real API ──
  async function signup({ name, email, phone, password, role }) {
    const res  = await fetch(`${API}/auth/signup`, {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({ name, email, phone, password, role }),
    });
    const data = await res.json();

    if (data.success) {
      // Save token and user to localStorage
      // so user stays logged in after refresh
      localStorage.setItem("bhojan_token", data.token);
      localStorage.setItem("bhojan_user",  JSON.stringify(data.user));
      setUser(data.user);
    }

    return data;
  }

  // ── Login — calls real API ──
  async function login({ email, password }) {
    const res  = await fetch(`${API}/auth/login`, {
      method:  "POST",
      headers: { "Content-Type": "application/json" },
      body:    JSON.stringify({ email, password }),
    });
    const data = await res.json();

    if (data.success) {
      localStorage.setItem("bhojan_token", data.token);
      localStorage.setItem("bhojan_user",  JSON.stringify(data.user));
      setUser(data.user);
    }

    return data;
  }

  // ── Logout ──
  function logout() {
    localStorage.removeItem("bhojan_token");
    localStorage.removeItem("bhojan_user");
    setUser(null);
  }

  // ── Helper: get token for API calls ──
  function getToken() {
    return localStorage.getItem("bhojan_token");
  }

  // Show nothing while checking login status
  if (loading) return null;

  return (
    <AuthContext.Provider value={{ user, login, signup, logout, getToken }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used inside <AuthProvider>");
  return ctx;
}
